module pipelined_multiplier (
    input clk,
    input [7:0] a,
    input [7:0] b,
    output reg [15:0] result
);
    reg [15:0] mul_result; // Intermediate result of multiplication

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        // First stage: multiply the inputs
        mul_result <= a * b;
    end

    always @(posedge clk) begin
        // Second stage: add constant
        result <= mul_result + 5;
    end
endmodule
